bitLocker:
$bitLocker = Invoke-Safe 'BitLocker' {
    Get-BitLockerVolume | ForEach-Object {
        [pscustomobject]@{
            Mount      = $_.MountPoint
            Protection = "$($_.ProtectionStatus)"
            Volume     = "$($_.VolumeStatus)"
            Percent    = $_.EncryptionPercentage
        }
    }
}
